<div><div class="mb-6"><h1 class="text-2xl font-bold text-slate-900">Kardex</h1><p class="text-sm text-slate-500">Consulta cronológica de movimientos y saldos.</p></div><div class="rounded-xl bg-white p-5 shadow-sm"><div class="grid gap-3 md:grid-cols-4"><select wire:model.live="productId" class="rounded-lg border-slate-300"><option value="">Seleccionar producto</option>@foreach($products as $product)<option value="{{ $product->id }}">{{ $product->name }} ({{ $product->code }})</option>@endforeach</select><select wire:model.live="locationId" class="rounded-lg border-slate-300"><option value="">Todas las ubicaciones</option>@foreach($locations as $location)<option value="{{ $location->id }}">{{ $location->name }}</option>@endforeach</select><input type="date" wire:model.live="from" class="rounded-lg border-slate-300"><input type="date" wire:model.live="to" class="rounded-lg border-slate-300"></div>@if($productId)<div class="mt-5 overflow-x-auto"><table class="w-full text-left text-sm"><thead class="border-b text-xs uppercase text-slate-500"><tr><th class="px-3 py-3">Fecha</th><th class="px-3 py-3">Tipo</th><th class="px-3 py-3">Dirección</th><th class="px-3 py-3">Cantidad</th><th class="px-3 py-3">Saldo</th><th class="px-3 py-3">Notas</th></tr></thead><tbody class="divide-y divide-slate-100">@forelse($movements as $movement)<tr><td class="px-3 py-3">{{ $movement->created_at?->format('d/m/Y H:i') }}</td><td class="px-3 py-3">{{ $movement->type->name }}</td><td class="px-3 py-3">{{ $movement->direction->name }}</td><td class="px-3 py-3">{{ $movement->quantity }}</td><td class="px-3 py-3 font-semibold">{{ $movement->balance_after }}</td><td class="px-3 py-3">{{ $movement->notes ?: '—' }}</td></tr>@empty<tr><td colspan="6" class="px-3 py-12 text-center text-slate-500">No hay movimientos para los filtros.</td></tr>@endforelse</tbody></table></div>@else<div class="py-12 text-center text-slate-500">Selecciona un producto para consultar su Kardex.</div>@endif</div></div>
